var numberGame = function(nums) {
    const s = [...nums].sort((a, b) => a - b);
    const arr = [];
    for (let i = 0; i < s.length; i += 2) {
        arr.push(s[i + 1]);
        arr.push(s[i]);
    }
    return arr;
};
